async (params, browser) => {
  // Open Telegram Web
  await browser.open('https://web.telegram.org/k/')

  // Wait for Telegram to load
  await browser.waitForSelector('.input-search input, .chatlist-chat, .chat-list', 15000)

  // Let app fully initialize
  await browser.wait(2000)

  // Search for the channel
  const search_channel = await browser.evaluate(`const searchInput = document.querySelector('.input-search input') || document.querySelector('input[type="text"]'); if (searchInput) { searchInput.focus(); searchInput.click(); await new Promise(r => setTimeout(r, 300)); searchInput.value = ''; searchInput.dispatchEvent(new Event('input', { bubbles: true })); document.execCommand('insertText', false, params.channel_name); searchInput.dispatchEvent(new Event('input', { bubbles: true })); } return { searched: true }`)

  // Wait for search results
  await browser.wait(2500)

  // Click on the matching channel
  const click_channel = await browser.evaluate(`const chatItems = document.querySelectorAll('.chatlist-chat, .chat-list .ListItem, .search-group .chatlist-chat'); let clicked = false; for (const item of chatItems) { const nameEl = item.querySelector('.peer-title, .user-title, .dialog-title'); if (nameEl && nameEl.textContent.trim().toLowerCase().includes(params.channel_name.toLowerCase())) { item.click(); clicked = true; break; } } if (!clicked && chatItems.length > 0) { chatItems[0].click(); clicked = true; } return { clicked: clicked }`)

  // Wait for channel to load
  await browser.wait(3000)

  // Wait for channel content
  await browser.waitForSelector('.bubble, .message, .chat-info', 10000)

  // Extract channel info
  const channel_info = await browser.evaluate(`const infoBtn = document.querySelector('.chat-info, .btn-icon.sidebar-header-btn, .chat-utils .btn-icon[class*="info"]'); if (infoBtn) infoBtn.click(); await new Promise(r => setTimeout(r, 1500)); const info = {}; const titleEl = document.querySelector('.chat-info .peer-title, .profile-content .peer-title, .top .peer-title'); info.name = titleEl ? titleEl.textContent.trim() : params.channel_name; const subtitleEl = document.querySelector('.chat-info .info, .profile-content .subtitle, .chat-info-subtitle, .profile-subtitle'); info.subscribers = subtitleEl ? subtitleEl.textContent.trim() : ''; const descEl = document.querySelector('.profile-content .bio, .profile-row .row-title, .section-content .bio'); info.description = descEl ? descEl.textContent.trim() : ''; const closeBtn = document.querySelector('.sidebar-close-button, .btn-icon.sidebar-close'); if (closeBtn) closeBtn.click(); return info`)

  await browser.wait(1000)

  // Extract channel messages
  const channel_messages = await browser.evaluate(`const messages = []; const bubbles = document.querySelectorAll('.bubble:not(.is-date), .message'); const startIdx = Math.max(0, bubbles.length - 20); for (let i = startIdx; i < bubbles.length; i++) { const el = bubbles[i]; const authorEl = el.querySelector('.peer-title, .name, .bubble-name .peer-title'); const contentEl = el.querySelector('.text-content, .message-content, .message'); const timeEl = el.querySelector('.time, time, .bubble-content .time'); const viewsEl = el.querySelector('.post-views, .message-views'); const content = contentEl ? contentEl.textContent.trim() : ''; if (!content) continue; messages.push({ author: authorEl ? authorEl.textContent.trim() : '', content: content, timestamp: timeEl ? timeEl.textContent.trim() : '', views: viewsEl ? viewsEl.textContent.trim() : '' }); } return { message_count: messages.length, messages: messages }`)

  return channel_messages
}
